// src/components/BookingSummary.jsx  (relevant additions shown)
import { saveBooking, generateRefCode } from '../store/bookingStore.js';
import { diffDays } from '../data/bookingData.js';

// Inside your component, replace the onSubmit prop usage like so:
// Pass this as onSubmit from the parent (e.g. App.jsx or BookingPage.jsx):

export function buildBookingPayload({
  checkIn, checkOut, bookingType, guests,
  guestName, guestContact, contactMethod,
  specialRequests = '',
}) {
  const selected = BOOKING_TYPES.find(t => t.id === bookingType);
  const nights = checkIn && checkOut ? diffDays(checkIn, checkOut) : 1;
  const weekend = isWeekend(checkIn);
  const rate = selected ? (weekend ? selected.weekendPrice : selected.weekdayPrice) : 0;

  return {
    id: generateRefCode(),
    createdAt: new Date().toISOString(),
    status: 'confirmed',
    paid: false,
    guestName,
    guestContact,
    contactMethod,
    guests,
    checkIn,
    checkOut: bookingType === 'overnight' ? checkOut : checkIn,
    nights: bookingType === 'overnight' ? nights : 1,
    room: selected ? { id: selected.id, name: selected.name, icon: selected.icon } : null,
    total: rate * (bookingType === 'overnight' ? nights : 1),
    specialRequests,
  };
}
